#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to calculate GCD using Euclidean algorithm
int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

// Function to calculate niceness of a sequence
long long calculateNiceness(int* arr, int n) {
    long long niceness = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            niceness += gcd(arr[i], arr[j]);
        }
    }
    return niceness;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, s;
        scanf("%d %d", &n, &s);
        int* arr = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        long long totalNiceness = 0;
        // Generate all possible sequences and calculate their niceness
        for (int i = 0; i < n; i++) {
            if (arr[i] == -1) {
                for (int j = 1; j <= s; j++) {
                    arr[i] = j;
                    totalNiceness += calculateNiceness(arr, n);
                    arr[i] = -1;
                }
            }
        }
        printf("%lld\n", totalNiceness % (1000000007));
    }
    return 0;
}

